mapper.select:
        select f.id, f.user_id, f.order_id, f.open_id, if(f.amount is not null, f.amount, 0) amount, f.`type`, f.status, f.token, f.`time`, f.remark, f.belongers_open_id, f.order_status
        /*,u.nickname*/
        ,o.order_type
        , o.product_identity_id
        ,o.`out_trade_no` out_trade_no

        /*p.`name` product_name,
        a.activity_name,
        pi.remark product_identity_name,*/
        ,IF(p.`name` IS NOT NULL,p.`name`, IF(a.activity_name IS NOT NULL,a.activity_name,IF(pi.remark IS NOT NULL,pi.remark,''))) product_name

        ,o.amount order_amount
        ,p.images
        from zhs_commission_flow f
        /*left join zhs_user u on f.open_id = u.token*/
        left join zhs_order o on f.order_id = o.id
        left join zhs_product p on o.product_id = p.id
        left join zhs_activity a on o.activity_id = a.id
        left join zhs_product_identity pi on o.product_identity_id = pi.id


                and
                    (
                        p.`name` like CONCAT("%", #{search}, "%")
                        or a.activity_name like CONCAT("%", #{search}, "%")
                        or pi.remark like CONCAT("%", #{search}, "%")
                        or o.out_trade_no like CONCAT("%", #{search}, "%")
                    )

             and f.user_id = #{userId}
             and f.order_id = #{orderId}
             and f.open_id = #{openId}
             and f.amount = #{amount}
             and f.`type` = #{type}
             and f.status = #{status}
             and f.token = #{token}
             and f.`time` = #{time}
             and f.`belongers_open_id` = #{belongersOpenId}
             and f.`order_status` = #{orderStatus}
             and f.`belongers_open_id` = #{tokenUuid}

        order by `time` desc
#         LIMIT 10

mapper.update:
update zhs_commission_flow
user_id = #{userId}, order_id = #{orderId}, open_id = #{openId}, amount = #{amount}, `type` = #{type}, status = #{status}, token = #{token}, `time` = #{time}, remark = #{remark}, belongers_open_id = #{belongersOpenId}, order_status = #{orderStatus},
where id = #{id}

mapper.select:
SELECT
    SUM(f.amount) total_income,
    SUM(IF(f.`status` = 0,f.amount,0)) current_amount
FROM
    `zhs_commission_flow` f
    /*left join `zhs_order` o on o.id = f.order_id*/
WHERE
    f.order_status = 2
    AND f.`status` != 1
    AND f.belongers_open_id = #{token}
    AND f.`time` <= #{endOfDay}
    /*and o.`status` = 3*/

SELECT
    SUM(f.amount) amount,
    SUM(IF(f.`order_status` = 0,f.amount,0)) incomplete,
    SUM(IF(f.`order_status` = 2 AND f.`status` != 1,f.amount,0)) finish,
    (
         SELECT COUNT(1) FROM zhs_commission_flow f1

             f1.belongers_open_id = #{token}
             AND f1.`status` != 1

                 AND f1.`time` >= #{nowBeginTime}


                 AND f1.`time` <= #{nowEndTime}


    ) `order`,

    (select sum(wd.`Withdrawal_amount`) from zhs_withdrawal_detail wd

        wd.open_id = #{token}

            AND wd.`Payment_time` >= #{nowBeginTime}


            AND wd.`Payment_time` <= #{nowEndTime}

    ) endAmount
FROM
    zhs_commission_flow f

    f.order_status = 2
     and f.belongers_open_id = #{token}

        AND f.`time` >= #{beginTime}


        AND f.`time` <= #{endTime}

SELECT
    (SELECT
        COUNT(1)
    FROM
        zhs_user u
        LEFT JOIN zhs_user pu ON u.parent_id = pu.invite_code


            AND pu.token = #{token}


            AND (u.nickname LIKE CONCAT('%',#{search},'%') or u.phone LIKE CONCAT(#{search},'%'))


            AND u.`created_at` <= #{beginTime}


            AND u.`created_at` >= #{endTime}

    )
    +
    (SELECT
        COUNT(1)
    FROM
        zhs_user u
        LEFT JOIN zhs_user pu ON u.parent_id = pu.invite_code
        LEFT JOIN zhs_user gu ON pu.parent_id = gu.invite_code


            AND gu.token = #{token}


            AND (u.nickname LIKE CONCAT('%',#{search},'%') or u.phone LIKE CONCAT(#{search},'%'))


            AND u.`created_at` <= #{beginTime}


            AND u.`created_at` >= #{endTime}

    )
